//! Functional test suite — end-to-end tests exercising the `voom` CLI binary
//! against real media files generated by `scripts/generate-test-corpus`.
//!
//! Gated behind `#[cfg(feature = "functional")]` so they never run during
//! normal `cargo test`. Invoke with:
//!
//! ```bash
//! cargo test -p voom-cli --features functional -- --test-threads=4
//! ```
//!
//! **Requirements**: `python3` and `ffmpeg` on PATH for corpus generation.
//! Individual tests may also require `ffprobe`, `mkvmerge`, or `mkvpropedit`.

#![cfg(feature = "functional")]

use assert_cmd::Command;
use predicates::prelude::*;
use std::path::{Path, PathBuf};
use std::sync::OnceLock;

// ═══════════════════════════════════════════════════════════════════════════
// Helpers
// ═══════════════════════════════════════════════════════════════════════════

/// Check if a tool is available on PATH.
fn has_tool(name: &str) -> bool {
    std::process::Command::new("which")
        .arg(name)
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .status()
        .map(|s| s.success())
        .unwrap_or(false)
}

/// Skip the current test if the named tool is not on PATH.
macro_rules! require_tool {
    ($tool:expr) => {
        if !has_tool($tool) {
            eprintln!("SKIPPED: {} not found on PATH", $tool);
            return;
        }
    };
}

/// A self-contained test environment with isolated config and data dirs.
struct TestEnv {
    _tempdir: tempfile::TempDir,
    config_home: PathBuf,
    voom_dir: PathBuf,
}

impl TestEnv {
    /// Create a new isolated environment with a minimal config.toml.
    fn new() -> Self {
        let tempdir = tempfile::tempdir().expect("create tempdir");
        let config_home = tempdir.path().join("config");
        let voom_dir = config_home.join("voom");
        std::fs::create_dir_all(&voom_dir).expect("create voom config dir");

        let config_toml = format!("data_dir = {:?}\n", voom_dir.display().to_string());
        let config_path = voom_dir.join("config.toml");
        std::fs::write(&config_path, &config_toml).expect("write config.toml");

        // Set restrictive permissions to avoid the "loose permissions" tracing warning
        // that would pollute stdout.
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            std::fs::set_permissions(&config_path, std::fs::Permissions::from_mode(0o600))
                .expect("set config.toml permissions");
        }

        TestEnv {
            _tempdir: tempdir,
            config_home,
            voom_dir,
        }
    }

    /// Return an `assert_cmd::Command` with isolated config via `XDG_CONFIG_HOME`.
    fn voom(&self) -> Command {
        let mut cmd = Command::cargo_bin("voom").expect("binary exists");
        cmd.env("XDG_CONFIG_HOME", &self.config_home);
        cmd.env("NO_COLOR", "1");
        cmd
    }

    /// Path to the media directory inside this environment.
    fn media_dir(&self) -> PathBuf {
        self._tempdir.path().join("media")
    }

    /// Copy specific corpus files (by stem) into this environment's media dir.
    /// Pass an empty slice to copy all files.
    fn populate_media(&self, stems: &[&str]) {
        let corpus = corpus_dir();
        let media = self.media_dir();
        std::fs::create_dir_all(&media).expect("create media dir");
        for entry in std::fs::read_dir(corpus).expect("read corpus dir") {
            let entry = entry.expect("dir entry");
            if !entry.path().is_file() {
                continue;
            }
            let name = entry.file_name();
            let name_str = name.to_string_lossy();
            if stems.is_empty() {
                std::fs::copy(entry.path(), media.join(&*name_str)).expect("copy file");
                continue;
            }
            let stem = Path::new(&*name_str)
                .file_stem()
                .map(|s| s.to_string_lossy().into_owned())
                .unwrap_or_default();
            if stems.iter().any(|s| *s == stem) {
                std::fs::copy(entry.path(), media.join(&*name_str)).expect("copy file");
            }
        }
    }

    /// Write a test policy file and return its path.
    fn write_policy(&self, name: &str, content: &str) -> PathBuf {
        let path = self.voom_dir.join(format!("{name}.voom"));
        std::fs::write(&path, content).expect("write policy");
        path
    }
}

// ═══════════════════════════════════════════════════════════════════════════
// Corpus generation (once per test run)
// ═══════════════════════════════════════════════════════════════════════════

static CORPUS: OnceLock<PathBuf> = OnceLock::new();

/// Get the path to the shared corpus directory, generating it on first call.
fn corpus_dir() -> &'static Path {
    CORPUS
        .get_or_init(|| {
            let dir = tempfile::tempdir().expect("create corpus tempdir");
            let path = dir.path().to_path_buf();
            // Leak so the dir lives for the entire process
            std::mem::forget(dir);

            let script = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
                .join("../../scripts/generate-test-corpus");

            assert!(
                script.exists(),
                "generate-test-corpus not found at {}",
                script.display()
            );

            let status = std::process::Command::new("python3")
                .arg(&script)
                .arg(&path)
                .arg("--duration")
                .arg("2")
                .arg("--seed")
                .arg("42")
                // Skip files needing rare encoders to keep CI green
                .arg("--skip")
                .arg("av1-opus,hevc-truehd")
                .status()
                .expect("run generate-test-corpus");

            if !status.success() {
                eprintln!(
                    "WARNING: generate-test-corpus had failures (exit {:?})",
                    status.code()
                );
            }

            assert!(
                path.join("basic-h264-aac.mp4").exists(),
                "corpus generation failed: basic-h264-aac.mp4 not found in {}",
                path.display()
            );

            path
        })
        .as_path()
}

/// Simple test policy for process tests.
const TEST_POLICY: &str = r#"
policy "test-normalize" {
  config {
    languages audio: [eng, und]
    languages subtitle: [eng, und]
    on_error: continue
  }

  phase normalize {
    keep audio where lang in [eng, und]
    keep subtitles where lang in [eng, und]

    defaults {
      audio: first_per_language
      subtitle: none
    }
  }
}
"#;

// ═══════════════════════════════════════════════════════════════════════════
// test_init
// ═══════════════════════════════════════════════════════════════════════════

mod test_init {
    use super::*;

    #[test]
    fn init_creates_config_and_dirs() {
        let env = TestEnv::new();
        // Remove the auto-created config so init has work to do
        std::fs::remove_dir_all(&env.voom_dir).unwrap();

        env.voom().arg("init").assert().success();

        assert!(env.voom_dir.join("config.toml").exists());
        assert!(env.voom_dir.join("policies").exists());
        assert!(env.voom_dir.join("policies/default.voom").exists());
    }

    #[test]
    fn init_is_idempotent() {
        let env = TestEnv::new();
        std::fs::remove_dir_all(&env.voom_dir).unwrap();

        env.voom().arg("init").assert().success();
        env.voom()
            .arg("init")
            .assert()
            .success()
            .stdout(predicate::str::contains("already exists"));
    }
}

