// ═══════════════════════════════════════════════════════════════════════════
// test_scan
// ═══════════════════════════════════════════════════════════════════════════

mod test_scan {
    use super::*;

    #[test]
    fn scan_discovers_media_files() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["basic-h264-aac", "hevc-surround"]);

        env.voom()
            .args(["scan", env.media_dir().to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success()
            .stdout(predicate::str::contains("2 files discovered"));
    }

    #[test]
    fn scan_with_no_hash() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["basic-h264-aac"]);

        env.voom()
            .args(["scan", env.media_dir().to_str().unwrap(), "--no-hash"])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success()
            .stdout(predicate::str::contains("hashing skipped"));
    }

    #[test]
    fn scan_empty_directory() {
        let env = TestEnv::new();
        std::fs::create_dir_all(env.media_dir()).unwrap();

        env.voom()
            .args(["scan", env.media_dir().to_str().unwrap()])
            .assert()
            .success()
            .stdout(predicate::str::contains("No media files found"));
    }

    #[test]
    fn scan_nonexistent_path_fails() {
        let env = TestEnv::new();
        env.voom()
            .args(["scan", "/nonexistent/path/to/media"])
            .assert()
            .failure();
    }

    #[test]
    fn scan_populates_database() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["basic-h264-aac"]);

        env.voom()
            .args(["scan", env.media_dir().to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success();

        env.voom()
            .arg("status")
            .assert()
            .success()
            .stdout(predicate::str::contains("1 files"));
    }
}

// ═══════════════════════════════════════════════════════════════════════════
// test_inspect
// ═══════════════════════════════════════════════════════════════════════════

mod test_inspect {
    use super::*;

    #[test]
    fn inspect_shows_metadata() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["hevc-surround"]);
        let file = env.media_dir().join("hevc-surround.mkv");

        env.voom()
            .args(["inspect", file.to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(30))
            .assert()
            .success()
            .stdout(
                predicate::str::contains("hevc")
                    .or(predicate::str::contains("h265"))
                    .or(predicate::str::contains("HEVC")),
            );
    }

    #[test]
    fn inspect_json_format() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["basic-h264-aac"]);
        let file = env.media_dir().join("basic-h264-aac.mp4");

        // Scan first so the file is in the DB (avoids "introspecting..." prefix in output)
        env.voom()
            .args(["scan", env.media_dir().to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success();

        let output = env
            .voom()
            .args(["inspect", file.to_str().unwrap(), "--format", "json"])
            .timeout(std::time::Duration::from_secs(30))
            .output()
            .expect("run inspect");

        assert!(output.status.success());
        let stdout = String::from_utf8_lossy(&output.stdout);
        let _: serde_json::Value =
            serde_json::from_str(&stdout).expect("inspect --format json should produce valid JSON");
    }

    #[test]
    fn inspect_from_database_after_scan() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["basic-h264-aac"]);
        let file = env.media_dir().join("basic-h264-aac.mp4");

        // Scan first to populate DB
        env.voom()
            .args(["scan", env.media_dir().to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success();

        // Inspect should hit DB (no "introspecting" message)
        env.voom()
            .args(["inspect", file.to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(30))
            .assert()
            .success()
            .stdout(predicate::str::contains("introspecting").not());
    }

    #[test]
    fn inspect_multitrack_file() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["hevc-surround"]);
        let file = env.media_dir().join("hevc-surround.mkv");

        // hevc-surround.mkv: 1 video, 2 audio (ac3 + aac), 2 subtitles
        env.voom()
            .args(["inspect", file.to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(30))
            .assert()
            .success()
            .stdout(
                predicate::str::contains("ac3")
                    .or(predicate::str::contains("aac"))
                    .or(predicate::str::contains("Audio")),
            );
    }
}

// ═══════════════════════════════════════════════════════════════════════════
// test_process
// ═══════════════════════════════════════════════════════════════════════════

mod test_process {
    use super::*;

    #[test]
    fn process_dry_run() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["hevc-surround"]);
        let policy = env.write_policy("test", TEST_POLICY);

        env.voom()
            .args([
                "process",
                env.media_dir().to_str().unwrap(),
                "--policy",
                policy.to_str().unwrap(),
                "--dry-run",
            ])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success()
            .stdout(predicate::str::contains("Dry-running"))
            .stdout(predicate::str::contains("dry run"));
    }

    #[test]
    fn process_dry_run_no_files_modified() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["basic-h264-aac"]);
        let policy = env.write_policy("test", TEST_POLICY);
        let file = env.media_dir().join("basic-h264-aac.mp4");

        let before = std::fs::read(&file).unwrap();

        env.voom()
            .args([
                "process",
                env.media_dir().to_str().unwrap(),
                "--policy",
                policy.to_str().unwrap(),
                "--dry-run",
            ])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success();

        let after = std::fs::read(&file).unwrap();
        assert_eq!(before, after, "dry-run must not modify files");
    }

    #[test]
    fn process_live_with_mkvtoolnix() {
        require_tool!("ffprobe");
        require_tool!("mkvmerge");
        require_tool!("mkvpropedit");
        let env = TestEnv::new();
        env.populate_media(&["hevc-surround"]);
        let policy = env.write_policy("test", TEST_POLICY);

        env.voom()
            .args([
                "process",
                env.media_dir().to_str().unwrap(),
                "--policy",
                policy.to_str().unwrap(),
                "--no-backup",
            ])
            .timeout(std::time::Duration::from_secs(120))
            .assert()
            .success()
            .stdout(predicate::str::contains("Applying"));
    }

    #[test]
    fn process_empty_directory() {
        let env = TestEnv::new();
        std::fs::create_dir_all(env.media_dir()).unwrap();
        let policy = env.write_policy("test", TEST_POLICY);

        env.voom()
            .args([
                "process",
                env.media_dir().to_str().unwrap(),
                "--policy",
                policy.to_str().unwrap(),
            ])
            .assert()
            .success()
            .stdout(predicate::str::contains("No media files found"));
    }

    #[test]
    fn process_invalid_policy_fails() {
        let env = TestEnv::new();
        std::fs::create_dir_all(env.media_dir()).unwrap();
        let bad = env.write_policy("bad", "not valid voom");

        env.voom()
            .args([
                "process",
                env.media_dir().to_str().unwrap(),
                "--policy",
                bad.to_str().unwrap(),
            ])
            .assert()
            .failure();
    }
}

