// test_policy
// ═══════════════════════════════════════════════════════════════════════════

mod test_policy {
    use super::*;

    fn fixture_path(name: &str) -> PathBuf {
        PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("../../crates/voom-dsl/tests/fixtures")
            .join(name)
    }

    #[test]
    fn policy_validate_valid() {
        let env = TestEnv::new();
        let fixture = fixture_path("production-normalize.voom");
        assert!(fixture.exists());

        env.voom()
            .args(["policy", "validate", fixture.to_str().unwrap()])
            .assert()
            .success()
            .stdout(predicate::str::contains("OK"));
    }

    #[test]
    fn policy_validate_invalid() {
        let env = TestEnv::new();
        let bad = env.write_policy("bad", "garbage syntax");

        env.voom()
            .args(["policy", "validate", bad.to_str().unwrap()])
            .assert()
            .failure();
    }

    #[test]
    fn policy_show_compiled() {
        let env = TestEnv::new();
        let fixture = fixture_path("production-normalize.voom");

        env.voom()
            .args(["policy", "show", fixture.to_str().unwrap()])
            .assert()
            .success()
            .stdout(predicate::str::contains("production-normalize"));
    }

    #[test]
    fn policy_format_roundtrip() {
        let env = TestEnv::new();
        let fixture = fixture_path("production-normalize.voom");
        let copy = env.voom_dir.join("format-test.voom");
        std::fs::copy(&fixture, &copy).unwrap();

        env.voom()
            .args(["policy", "format", copy.to_str().unwrap()])
            .assert()
            .success();

        // Formatted file should still validate
        env.voom()
            .args(["policy", "validate", copy.to_str().unwrap()])
            .assert()
            .success();
    }

    #[test]
    fn policy_validate_full_pipeline() {
        let env = TestEnv::new();
        let fixture = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("../../docs/examples/full-pipeline.voom");

        env.voom()
            .args(["policy", "validate", fixture.to_str().unwrap()])
            .assert()
            .success()
            .stdout(predicate::str::contains("OK"));
    }
}

