// ═══════════════════════════════════════════════════════════════════════════
// test_workflow — multi-step end-to-end scenarios
// ═══════════════════════════════════════════════════════════════════════════

mod test_workflow {
    use super::*;

    /// Full lifecycle: init → scan → inspect → process --dry-run → report → status
    #[test]
    fn full_lifecycle_dry_run() {
        require_tool!("ffprobe");
        let env = TestEnv::new();

        // Remove config dir to test init
        std::fs::remove_dir_all(&env.voom_dir).unwrap();

        // 1. Init
        env.voom().arg("init").assert().success();

        // 2. Populate media
        env.populate_media(&["hevc-surround", "basic-h264-aac"]);

        // 3. Scan
        env.voom()
            .args(["scan", env.media_dir().to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success()
            .stdout(predicate::str::contains("2 files discovered"));

        // 4. Inspect (should hit DB)
        let mkv = env.media_dir().join("hevc-surround.mkv");
        env.voom()
            .args(["inspect", mkv.to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(30))
            .assert()
            .success();

        // 5. Process dry-run with the starter policy from init
        let starter = env.voom_dir.join("policies/default.voom");
        assert!(starter.exists(), "init should create default.voom");
        env.voom()
            .args([
                "process",
                env.media_dir().to_str().unwrap(),
                "--policy",
                starter.to_str().unwrap(),
                "--dry-run",
            ])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success()
            .stdout(predicate::str::contains("dry run"));

        // 6. Report
        env.voom()
            .arg("report")
            .assert()
            .success()
            .stdout(predicate::str::contains("2 files"));

        // 7. Status
        env.voom()
            .arg("status")
            .assert()
            .success()
            .stdout(predicate::str::contains("2 files"));
    }

    /// Scan → delete file → prune → verify status
    #[test]
    fn scan_prune_rescan() {
        require_tool!("ffprobe");
        let env = TestEnv::new();
        env.populate_media(&["basic-h264-aac", "hevc-surround"]);

        // Scan
        env.voom()
            .args(["scan", env.media_dir().to_str().unwrap()])
            .timeout(std::time::Duration::from_secs(60))
            .assert()
            .success();

        // Delete one file
        std::fs::remove_file(env.media_dir().join("basic-h264-aac.mp4")).unwrap();

        // Prune
        env.voom().args(["db", "prune"]).assert().success();

        // Status should show 1 file
        env.voom()
            .arg("status")
            .assert()
            .success()
            .stdout(predicate::str::contains("1 files"));
    }
}
